<template>
  <div class="batch-password-tool">
    <el-card>
      <div slot="header">
        <span>批量密码生成器</span>
        <el-tag v-if="backendAvailable" type="success" size="small" style="margin-left: 10px">后端可用</el-tag>
        <el-tag v-else type="danger" size="small" style="margin-left: 10px">后端不可用</el-tag>
      </div>

      <el-row :gutter="20">
        <el-col :span="8">
          <el-form label-width="100px">
            <el-form-item label="密码长度">
              <el-slider v-model="config.length" :min="4" :max="64" show-input />
            </el-form-item>

            <el-form-item label="生成数量">
              <el-slider v-model="config.count" :min="1" :max="100" show-input />
            </el-form-item>

            <el-divider>字符类型</el-divider>

            <el-form-item label="大写字母">
              <el-switch v-model="config.includeUpper" />
              <span class="char-preview">A-Z</span>
            </el-form-item>

            <el-form-item label="小写字母">
              <el-switch v-model="config.includeLower" />
              <span class="char-preview">a-z</span>
            </el-form-item>

            <el-form-item label="数字">
              <el-switch v-model="config.includeNumbers" />
              <span class="char-preview">0-9</span>
            </el-form-item>

            <el-form-item label="特殊字符">
              <el-switch v-model="config.includeSymbols" />
              <span class="char-preview">!@#$%^&*</span>
            </el-form-item>

            <el-form-item label="自定义字符">
              <el-input v-model="config.customChars" placeholder="自定义字符集" />
            </el-form-item>

            <el-form-item label="排除字符">
              <el-input v-model="config.excludeChars" placeholder="要排除的字符" />
            </el-form-item>
          </el-form>
        </el-col>

        <el-col :span="8">
          <el-divider>密码强度预览</el-divider>
          <div class="strength-preview">
            <el-progress :percentage="strengthScore" :color="strengthColor" :stroke-width="20" />
            <div class="strength-label" :style="{ color: strengthColor }">{{ strengthLabel }}</div>
          </div>

          <el-divider>生成选项</el-divider>
          <el-form label-width="100px">
            <el-form-item label="避免歧义">
              <el-switch v-model="config.avoidAmbiguous" />
              <div class="option-hint">排除 l, 1, I, O, 0 等易混淆字符</div>
            </el-form-item>

            <el-form-item label="必须包含">
              <el-checkbox-group v-model="config.mustInclude">
                <el-checkbox label="upper">大写</el-checkbox>
                <el-checkbox label="lower">小写</el-checkbox>
                <el-checkbox label="number">数字</el-checkbox>
                <el-checkbox label="symbol">符号</el-checkbox>
              </el-checkbox-group>
            </el-form-item>

            <el-form-item label="开头字符">
              <el-select v-model="config.startWith" clearable placeholder="选择开头字符类型">
                <el-option label="字母" value="letter" />
                <el-option label="数字" value="number" />
                <el-option label="符号" value="symbol" />
              </el-select>
            </el-form-item>
          </el-form>

          <div class="action-buttons">
            <el-button type="primary" @click="generatePasswords" :loading="generating">
              生成密码
            </el-button>
            <el-button @click="reset">重置</el-button>
          </div>
        </el-col>

        <el-col :span="8">
          <div class="section-header">
            <span>生成的密码</span>
            <el-button type="text" @click="copyAll">复制全部</el-button>
          </div>
          <el-input
            v-model="passwords"
            type="textarea"
            :rows="20"
            readonly
            placeholder="生成的密码将显示在这里..."
          />
          <div class="result-actions">
            <el-button type="success" @click="exportPasswords" :disabled="!passwords">
              导出为文件
            </el-button>
            <el-button @click="clearPasswords">清空</el-button>
          </div>
        </el-col>
      </el-row>
    </el-card>
  </div>
</template>

<script>
export default {
  name: 'BatchPasswordTool',
  data() {
    return {
      config: {
        length: 16,
        count: 10,
        includeUpper: true,
        includeLower: true,
        includeNumbers: true,
        includeSymbols: true,
        customChars: '',
        excludeChars: '',
        avoidAmbiguous: false,
        mustInclude: [],
        startWith: ''
      },
      passwords: '',
      generating: false,
      backendAvailable: false
    }
  },
  computed: {
    strengthScore() {
      let score = 0
      if (this.config.length >= 8) score += 20
      if (this.config.length >= 12) score += 10
      if (this.config.length >= 16) score += 10
      if (this.config.includeUpper) score += 15
      if (this.config.includeLower) score += 15
      if (this.config.includeNumbers) score += 15
      if (this.config.includeSymbols) score += 15
      return Math.min(score, 100)
    },
    strengthColor() {
      if (this.strengthScore < 40) return '#F56C6C'
      if (this.strengthScore < 70) return '#E6A23C'
      return '#67C23A'
    },
    strengthLabel() {
      if (this.strengthScore < 40) return '弱'
      if (this.strengthScore < 70) return '中等'
      return '强'
    }
  },
  mounted() {
    this.checkBackend()
  },
  methods: {
    async checkBackend() {
      try {
        const response = await fetch('/api/ping')
        this.backendAvailable = response.ok
      } catch (e) {
        this.backendAvailable = false
      }
    },
    async generatePasswords() {
      this.generating = true

      try {
        let passwordList = []

        if (this.backendAvailable) {
          passwordList = await this.generateBackend()
        } else {
          passwordList = this.generateFrontend()
        }

        this.passwords = passwordList.join('\n')
        this.$message.success(`成功生成 ${passwordList.length} 个密码`)
      } catch (e) {
        this.$message.error('生成失败: ' + e.message)
      } finally {
        this.generating = false
      }
    },
    async generateBackend() {
      const params = new URLSearchParams({
        length: this.config.length,
        includeUpper: this.config.includeUpper,
        includeLower: this.config.includeLower,
        includeNumbers: this.config.includeNumbers,
        includeSymbols: this.config.includeSymbols,
        count: this.config.count
      })

      const response = await fetch(`/api/random/password?${params}`)
      const result = await response.json()

      if (result.success) {
        return result.passwords
      } else {
        throw new Error(result.error)
      }
    },
    generateFrontend() {
      const upper = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'
      const lower = 'abcdefghijklmnopqrstuvwxyz'
      const numbers = '0123456789'
      const symbols = '!@#$%^&*()_+-=[]{}|;:,.<>?'
      const ambiguous = 'l1IO0'

      let chars = ''
      if (this.config.includeUpper) chars += upper
      if (this.config.includeLower) chars += lower
      if (this.config.includeNumbers) chars += numbers
      if (this.config.includeSymbols) chars += symbols

      if (this.config.customChars) {
        chars = this.config.customChars
      }

      if (this.config.avoidAmbiguous) {
        chars = chars.split('').filter(c => !ambiguous.includes(c)).join('')
      }

      if (this.config.excludeChars) {
        const excludeSet = new Set(this.config.excludeChars.split(''))
        chars = chars.split('').filter(c => !excludeSet.has(c)).join('')
      }

      if (!chars) {
        throw new Error('请至少选择一种字符类型')
      }

      const passwords = []
      const crypto = window.crypto || window.msCrypto
      const randomValues = new Uint32Array(this.config.length)

      for (let i = 0; i < this.config.count; i++) {
        crypto.getRandomValues(randomValues)
        let password = ''
        
        for (let j = 0; j < this.config.length; j++) {
          password += chars[randomValues[j] % chars.length]
        }

        if (this.config.startWith) {
          const startChars = {
            letter: upper + lower,
            number: numbers,
            symbol: symbols
          }
          const startCharSet = startChars[this.config.startWith] || chars
          const startChar = startCharSet[Math.floor(Math.random() * startCharSet.length)]
          password = startChar + password.substring(1)
        }

        passwords.push(password)
      }

      return passwords
    },
    copyAll() {
      if (!this.passwords) {
        this.$message.warning('没有可复制的内容')
        return
      }
      navigator.clipboard.writeText(this.passwords).then(() => {
        this.$message.success('已复制到剪贴板')
      })
    },
    exportPasswords() {
      if (!this.passwords) return
      
      const blob = new Blob([this.passwords], { type: 'text/plain' })
      const url = URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = `passwords_${Date.now()}.txt`
      link.click()
      URL.revokeObjectURL(url)
    },
    clearPasswords() {
      this.passwords = ''
    },
    reset() {
      this.config = {
        length: 16,
        count: 10,
        includeUpper: true,
        includeLower: true,
        includeNumbers: true,
        includeSymbols: true,
        customChars: '',
        excludeChars: '',
        avoidAmbiguous: false,
        mustInclude: [],
        startWith: ''
      }
      this.passwords = ''
    }
  }
}
</script>

<style scoped>
.batch-password-tool {
  padding: 20px;
}

.char-preview {
  font-family: monospace;
  color: #909399;
  font-size: 12px;
  margin-left: 10px;
}

.option-hint {
  font-size: 11px;
  color: #909399;
  margin-top: 5px;
}

.strength-preview {
  text-align: center;
  padding: 20px;
  background: #f5f7fa;
  border-radius: 8px;
}

.strength-label {
  font-size: 24px;
  font-weight: bold;
  margin-top: 10px;
}

.section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
}

.action-buttons {
  text-align: center;
  margin-top: 20px;
}

.result-actions {
  margin-top: 10px;
  text-align: center;
}
</style>
